text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 한다.",
        "conditions": [
          "스모크 테스트 통과"
        ],
        "source_certainty": "확정"
      },
      {
        "topic": "packageName mismatch 대응",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "source_certainty": "확정"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "기각",
        "source_certainty": "확정"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐, 최종 공개 릴리스 결정 아님",
        "source_certainty": "확정"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자가 지정되지 않았다.",
        "source_certainty": "확정"
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "source_certainty": "확정"
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "확정"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미결",
        "source_certainty": "확정"
      },
      {
        "question": "릴리스 노트에 수요일 내부 스트레치 목표를 언급해야 하는가?",
        "status": "미결",
        "source_certainty": "확정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "민준 결과 공유 후, 정확한 기한 미정",
      "status": "확정",
      "source_certainty": "확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과 통과 여부를 확인한다.",
      "Doyun의 실패 트리아지 노트 작성 여부를 확인한다.",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 결정 사항으로 추적한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "지정되지 않은 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "고객명, 외부 파트너, 예산, 보안, 장애, 법무 관련 사실은 언급되지 않았으므로 추가하지 않는다.",
    "확정되지 않은 제안은 결정으로 기록하지 않는다.",
    "내부 스트레치 목표와 공개 릴리스 결정은 구분한다.",
    "담당자나 기한이 명시되지 않은 항목은 임의로 보완하지 않는다.",
    "오픈 질문은 답이 정해진 것처럼 서술하지 않는다."
  ]
}
